package sn.gestionimmobiliere.backend.receipt.api;import java.util.UUID;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import io.swagger.v3.oas.annotations.tags.Tag;import sn.gestionimmobiliere.backend.receipt.application.ReceiptService;@RestController @Tag(name="Receipts")public class ReceiptController{private final ReceiptService service;public ReceiptController(ReceiptService s){service=s;}@PostMapping("/api/rent-charges/{id}/receipt")public ReceiptResponse issue(@PathVariable UUID id){return service.issue(id);}@GetMapping("/api/receipts/{id}/pdf")public ResponseEntity<byte[]> pdf(@PathVariable UUID id){return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=quittance.pdf").contentType(MediaType.APPLICATION_PDF).body(service.pdf(id));}}
